t.t:
.opp-table { width: 100%; border-collapse: collapse; background: var(--bg-card); border-radius: 10px; overflow: hidden; border: 1px solid var(--border); }
.opp-table th { text-align: left; padding: 11px 16px; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-muted); background: #F8FAFC; border-bottom: 1px solid var(--border); }
.opp-table td { padding: 13px 16px; font-size: 13.5px; border-bottom: 1px solid var(--border); vertical-align: middle; }
.opp-table tr:last-child td { border-bottom: none; }
.opp-table tr:hover td { background: #F8FAFC; }
.cand-pill { display: inline-flex; align-items: center; gap: 5px; padding: 3px 10px; border-radius: 20px; font-size: 12px; font-weight: 600; background: var(--primary-light); color: var(--primary); }
.cand-pill.zero { background: #F2F4F7; color: var(--text-muted); }
.row-actions { display: flex; gap: 6px; }
.deadline-ok   { color: #1D9E75; font-size: 12.5px; }
.deadline-warn { color: #BA7517; font-size: 12.5px; }
.deadline-over { color: #D85A30; font-size: 12.5px; }

.opp-info-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 22px 26px; margin-bottom: 24px; display: flex; gap: 32px; flex-wrap: wrap; align-items: flex-start; }
.opp-info-block { display: flex; flex-direction: column; gap: 3px; }
.opp-info-label { font-size: 10.5px; text-transform: uppercase; letter-spacing: 0.08em; color: var(--text-muted); font-weight: 700; }
.opp-info-value { font-size: 14px; color: var(--text-primary); font-weight: 500; }
.opp-desc-card { background: var(--primary-light); border-left: 4px solid var(--primary); border-radius: 0 8px 8px 0; padding: 14px 18px; margin-bottom: 24px; font-size: 13.5px; color: var(--text-primary); line-height: 1.6; }
.section-title { font-size: 16px; font-weight: 700; color: var(--text-primary); margin-bottom: 14px; display: flex; align-items: center; gap: 10px; }
.section-title .count-badge { font-size: 12px; background: var(--primary-light); color: var(--primary); padding: 2px 10px; border-radius: 20px; font-weight: 600; }
.cand-table { width: 100%; border-collapse: collapse; background: var(--bg-card); border-radius: 10px; overflow: hidden; border: 1px solid var(--border); }
.cand-table th { text-align: left; padding: 10px 16px; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-muted); background: #F8FAFC; border-bottom: 1px solid var(--border); }
.cand-table td { padding: 12px 16px; font-size: 13.5px; border-bottom: 1px solid var(--border); vertical-align: middle; }
.cand-table tr:last-child td { border-bottom: none; }
.cand-table tr:hover td { background: #F8FAFC; cursor: pointer; }
.avatar-circle { width: 32px; height: 32px; border-radius: 50%; background: var(--primary-light); color: var(--primary); font-size: 11px; font-weight: 700; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.name-cell { display: flex; align-items: center; gap: 10px; }
.stage-badge { display: inline-flex; padding: 3px 10px; border-radius: 20px; font-size: 11.5px; font-weight: 600; }
.stage-novo      { background: #E6F1FB; color: #0F4C81; }
.stage-analise   { background: #EEEDFE; color: #3C3489; }
.stage-aprovado  { background: #E1F5EE; color: #0F6E56; }
.stage-rejeitado { background: #FAECE7; color: #993C1D; }
.empty-cands { text-align: center; padding: 48px 20px; color: var(--text-muted); }
.empty-cands p { font-size: 14px; margin-bottom: 12px; }

.detalhe-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 24px; }
@media(max-width:700px) { .detalhe-grid { grid-template-columns: 1fr; } }
.info-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 22px; }
.info-card h3 { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; color: var(--text-muted); margin-bottom: 16px; padding-bottom: 10px; border-bottom: 1px solid var(--border); }
.info-row { display: flex; justify-content: space-between; align-items: center; padding: 8px 0; border-bottom: 1px solid #F2F4F7; font-size: 13.5px; }
.info-row:last-child { border-bottom: none; }
.info-row .lbl { color: var(--text-muted); }
.info-row .val { font-weight: 500; color: var(--text-primary); text-align: right; max-width: 60%; }
.motiv-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 22px; margin-bottom: 24px; }
.motiv-card h3 { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; color: var(--text-muted); margin-bottom: 14px; }
.motiv-text { font-size: 14px; color: var(--text-primary); line-height: 1.7; white-space: pre-line; }
.motiv-empty { font-size: 13.5px; color: var(--text-muted); font-style: italic; }
.stage-actions { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 20px 22px; display: flex; align-items: center; gap: 12px; flex-wrap: wrap; }
.stage-actions .lbl { font-size: 13px; font-weight: 600; color: var(--text-primary); flex: 1; }
.stage-current { display: inline-flex; padding: 4px 12px; border-radius: 20px; font-size: 13px; font-weight: 600; margin-right: 8px; }
.stage-novo      { background: #E6F1FB; color: #0F4C81; }
.stage-analise   { background: #EEEDFE; color: #3C3489; }
.stage-aprovado  { background: #E1F5EE; color: #0F6E56; }
.stage-rejeitado { background: #FAECE7; color: #993C1D; }
.btn-analise  { background: #534AB7; color:#fff; }
.btn-aprovar  { background: #1D9E75; color:#fff; }
.btn-rejeitar { background: #D85A30; color:#fff; }
.btn-novo     { background: #5A6475; color:#fff; }
.opp-ref { background: var(--primary-light); border-left: 4px solid var(--primary); border-radius: 0 8px 8px 0; padding: 12px 16px; margin-bottom: 20px; font-size: 13.5px; display: flex; align-items: center; gap: 12px; }
.opp-ref strong { color: var(--primary); }

t.script:
const LEAD_ID = ;
async function moverPara(stage) {
    const btns = document.querySelectorAll('.stage-actions .btn');
    btns.forEach(b => b.disabled = true);
    const res = await fetch('/api/candidaturas/move', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            jsonrpc: '2.0', method: 'call', id: 1,
            params: {lead_id: LEAD_ID, target_stage: stage}
        })
    });
    const json = await res.json();
    if (json.result && json.result.success) {
        location.reload();
    } else {
        alert('Erro: ' + (json.result?.message || 'Falha na comunicação'));
        btns.forEach(b => b.disabled = false);
    }
}
